input.newString:
function getBasePremium(item: any): number {
  if (item.type === "sword") return 100;
  if (item.type === "amulet") return 60;
  if (item.type === "staff") return 80;
  if (item.type === "potion") return 40;
  if (item.type === "rune" || item.type === "moonstone") return 25;
  return 0;
}

export function quote(customer: Customer, items: any[]): number {
  if (items.length === 0) return PROCESSING_FEE;
  let basePremium = 0;
  for (const item of items) {
    basePremium += getBasePremium(item);
  }
  return basePremium + PROCESSING_FEE;
}

