const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

export function quote(customer: Customer, items: any[]): number {
  if (items.length === 0) return PROCESSING_FEE;
  const base = items.reduce((sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0), 0);
  return base + PROCESSING_FEE;
}

