input.newString:
export function quote(customer: Customer, items: any[], previousQuotes: number = 0): number {
  if (items.length === 0) return PROCESSING_FEE;

  let policyBase = 0;

  for (const item of items) {
    const itemBase = BASE_PREMIUMS[item.type] ?? 0;
    let itemPremium = itemBase;

    if (item.cursed) {
      itemPremium += itemBase * 0.5;
    }
    if (item.enchantment >= 5) {
      itemPremium += itemBase * 0.3;
    }

    policyBase += itemPremium;
  }

  // Policy-wide modifiers
  if (customer.yearsWithMHPCO >= 2) {
    policyBase *= 0.8;
  }

  // First insurance surcharge (applies to every quote)
  policyBase *= 1.1;

  // Follow-up contract discount
  if (previousQuotes > 0) {
    policyBase *= 0.85;
  }

  // Round up in MHPCO's favor
  const totalPremium = Math.ceil(policyBase) + PROCESSING_FEE;
  return totalPremium;
}

