function isComponent(type: string): boolean {
  return type === "rune" || type === "moonstone";
}

export function quote(customer: Customer, items: any[], previousQuotes: number = 0): number {
  if (items.length === 0) return PROCESSING_FEE;

  let policyBase = 0;

  // Process main items
  const mainItems = items.filter(i => !isComponent(i.type));
  for (const item of mainItems) {
    const itemBase = BASE_PREMIUMS[item.type] ?? 0;
    let itemPremium = itemBase;

    if (item.cursed) {
      itemPremium = precise(itemPremium + itemBase * 0.5);
    }
    if (item.enchantment >= 5) {
      itemPremium = precise(itemPremium + itemBase * 0.3);
    }

    policyBase += itemPremium;
  }

  // Process components with block discount
  const components = items.filter(i => isComponent(i.type));
  const componentGroups: Record<string, number> = {};
  for (const c of components) {
    componentGroups[c.type] = (componentGroups[c.type] || 0) + 1;
  }

  for (const [type, count] of Object.entries(componentGroups)) {
    if (count === COMPONENT_BLOCK_SIZE) {
      policyBase += COMPONENT_BLOCK_PREMIUM;
    } else {
      policyBase += count * (BASE_PREMIUMS[type] ?? 0);
    }
  }

  // Policy-wide modifiers
  if (customer.yearsWithMHPCO >= 2) {
    policyBase = precise(policyBase * 0.8);
  }

  // First insurance surcharge (applies to every quote)
  policyBase = precise(policyBase * 1.1);

  // Follow-up contract discount
  if (previousQuotes > 0) {
    policyBase = precise(policyBase * 0.85);
  }

  // Round up in MHPCO's favor
  const totalPremium = Math.ceil(policyBase) + PROCESSING_FEE;
  return totalPremium;
}

