// Rounding
it("should round premium UP in MHPCO's favor -- 197.5 → 198", () => {
  // 175 base + 10% first insurance = 192.5, but we need 197.5 before rounding
  // Let's use a case that produces 197.5: e.g. base 175 + cursed 87.5 = 262.5, with loyalty 20% = 210, +10% = 231... 
  // Actually let's construct: base needs to be such that after modifiers we get 197.5
  // 197.5 / 1.1 = 179.545... not clean
  // Let's test with a simpler approach: 2 runes (50 base) + cursed sword (150) = 200 base
  // loyalty (2 years): 200 * 0.8 = 160, first insurance: 160 * 1.1 = 176, +5 = 181
  // Hmm. Let's just test a case where we know rounding matters.
  // A potion (40) with high enchantment (40*1.3=52) = 52, first insurance = 57.2, ceil=58, +5=63
  // Not 197.5. Let's construct: we need base + modifiers = 192.5 before fee
  // 192.5 / 1.1 = 175. So policy base before first insurance should be 175
  // 175 could be: 7 runes (175 base) with no other modifiers
  // 175 * 1.1 = 192.5, ceil = 193, +5 = 198
  expect(quote({ yearsWithMHPCO: 0 }, Array(7).fill({ type: "rune" }), 0)).toBe(198);
});
it.todo("should round payout DOWN in MHPCO's favor -- 350.5 → 350");

